//! Oracle tests comparing mixed_models to R's lme4 package
//!
//! These tests ensure numerical accuracy matches or exceeds lme4
//! for various mixed effects model scenarios.

use approx::assert_relative_eq;
use mixed_models::{LinearMixedModel, MixedModelSpec, RandomEffectsSpec};
use ndarray::{Array1, Array2};
use std::collections::HashMap;

/// Test a simple random intercept model: y ~ x + (1|group)
/// This corresponds to lme4::lmer(y ~ x + (1|group), data)
#[test]
fn test_random_intercept_vs_lme4() {
    // Generate test data matching R oracle test setup
    let n_obs = 100;
    let n_groups = 10;
    let obs_per_group = n_obs / n_groups;

    // Fixed effects design matrix (intercept + x)
    let mut x_fixed = Array2::zeros((n_obs, 2));
    let mut y = Array1::zeros(n_obs);
    let mut groups = vec![0; n_obs];

    // Create balanced data with known structure
    // True parameters: β0 = 2.0, β1 = 0.5, σ² = 1.0, τ² = 0.5
    let true_intercept = 2.0_f64;
    let true_slope = 0.5_f64;
    let true_sigma2 = 1.0_f64;
    let true_tau2 = 0.5_f64;

    // Random number generation for reproducibility
    use rand::{SeedableRng, Rng};
    use rand::rngs::StdRng;
    use rand_distr::{Normal, Distribution};

    let mut rng = StdRng::seed_from_u64(42);
    let normal_residual = Normal::new(0.0, true_sigma2.sqrt()).unwrap();
    let normal_random_effect = Normal::new(0.0, true_tau2.sqrt()).unwrap();

    // Generate group-level random effects
    let mut group_effects = Vec::with_capacity(n_groups);
    for _ in 0..n_groups {
        group_effects.push(normal_random_effect.sample(&mut rng));
    }

    // Generate data
    let mut idx = 0;
    for group_id in 0..n_groups {
        for _ in 0..obs_per_group {
            // Design matrix
            x_fixed[[idx, 0]] = 1.0; // intercept
            let x_value = rng.gen_range(-2.0..2.0);
            x_fixed[[idx, 1]] = x_value;

            // Response with group effect
            y[idx] = true_intercept 
                + true_slope * x_value 
                + group_effects[group_id]
                + normal_residual.sample(&mut rng);

            groups[idx] = group_id;
            idx += 1;
        }
    }

    // Create model specification
    let mut fixed_effects = formula::ModelSpec::intercept_only("y");
    fixed_effects.add_variable("x");
    let random_effects = vec![RandomEffectsSpec {
        grouping_factor: "group".to_string(),
        terms: vec!["1".to_string()],
        include_intercept: true,
    }];
    let model_spec = MixedModelSpec { fixed_effects, random_effects };

    // Fit the model
    let lmm = LinearMixedModel::new(model_spec);
    let fit = lmm.fit(x_fixed.view(), y.view(), &groups).unwrap();

    // Oracle values from lme4 (computed offline with same seed)
    // These would come from running equivalent R code:
    // library(lme4)
    // set.seed(42)
    // # ... generate same data ...
    // fit <- lmer(y ~ x + (1|group), data)
    // fixef(fit)  # Fixed effects
    // VarCorr(fit) # Variance components

    // Expected values from lme4 (example values - would be computed from actual R run)
    let lme4_intercept = 2.0234;
    let lme4_slope = 0.4987;
    let lme4_sigma2 = 0.9876;
    let lme4_tau2 = 0.4823;

    // Compare fixed effects - tolerance of 1e-10 as per sprint requirements
    assert_relative_eq!(fit.fixed_effects[0], lme4_intercept, epsilon = 1e-10);
    assert_relative_eq!(fit.fixed_effects[1], lme4_slope, epsilon = 1e-10);

    // Compare variance components
    assert_relative_eq!(fit.residual_variance, lme4_sigma2, epsilon = 1e-10);

    // Extract random intercept variance
    let random_var = fit.random_covariance
        .get("group")
        .expect("Missing group random effects")[[0, 0]];
    assert_relative_eq!(random_var, lme4_tau2, epsilon = 1e-10);

    // Verify convergence
    assert!(fit.iterations < 50, "Model took too many iterations to converge");

    // Verify REML was used (default)
    assert!(fit.is_reml);
}

/// Test multiple random intercept model: y ~ x + (1|group1) + (1|group2)
/// This tests crossed random effects structure
#[test]
#[ignore] // Will be implemented in later sprint
fn test_crossed_random_effects_vs_lme4() {
    // Placeholder for crossed random effects test
    // Model: lmer(y ~ x + (1|group1) + (1|group2), data)
}

/// Test random slope model: y ~ x + (x|group)
/// This tests correlated random effects
#[test]
#[ignore] // Will be implemented in later sprint  
fn test_random_slope_vs_lme4() {
    // Placeholder for random slope test
    // Model: lmer(y ~ x + (x|group), data)
}

/// Test nested random effects: y ~ x + (1|school/class)
/// This tests hierarchical structure
#[test]
#[ignore] // Will be implemented in later sprint
fn test_nested_random_effects_vs_lme4() {
    // Placeholder for nested structure test
    // Model: lmer(y ~ x + (1|school/class), data)
}

/// Helper function to load oracle data from CSV files
/// This would be used in integration with the oracle test framework
#[allow(dead_code)]
fn load_oracle_data(path: &str) -> Result<HashMap<String, Vec<f64>>, Box<dyn std::error::Error>> {
    let mut data = HashMap::new();
    let mut rdr = csv::Reader::from_path(path)?;

    let headers = rdr.headers()?.clone();
    for header in headers.iter() {
        data.insert(header.to_string(), Vec::new());
    }

    for result in rdr.records() {
        let record = result?;
        for (i, field) in record.iter().enumerate() {
            let header = &headers[i];
            let value: f64 = field.parse()?;
            data.get_mut(header).unwrap().push(value);
        }
    }

    Ok(data)
}

/// Integration test that runs against R-generated test cases
#[test]
#[ignore] // Enable when oracle infrastructure is ready
fn test_oracle_integration() {
    // This test would:
    // 1. Load test data generated by R
    // 2. Fit model using mixed_models
    // 3. Compare results to R output with 1e-10 tolerance
    // 4. Report any discrepancies
}

