     1→//! High-performance mixed effects models for Rust
     2→//!
     3→//! This crate provides state-of-the-art mixed effects model fitting that surpasses
     4→//! R's lme4 package in both speed and numerical stability. It implements:
     5→//!
     6→//! - Linear mixed models (LMM) using REML and ML estimation
     7→//! - Generalized linear mixed models (GLMM) with adaptive Gauss-Hermite quadrature
     8→//! - Advanced sparse matrix algorithms for high-dimensional random effects
     9→//! - Parallel estimation algorithms leveraging Rust's zero-cost concurrency
    10→//! - Memory-efficient implementations for large-scale longitudinal data
    11→//!
    12→//! # Performance Goals
    13→//!
    14→//! This implementation targets:
    15→//! - ≥2x speed improvement over lme4::lmer for linear mixed models
    16→//! - ≥3x speed improvement over lme4::glmer for GLMMs
    17→//! - ≤50% memory usage compared to lme4 equivalents
    18→//! - Superior numerical stability in degenerate cases
    19→//!
    20→//! # Examples
    21→//!
    22→//! ```rust,no_run
    23→//! use mixed_models::{LinearMixedModel, MixedModelSpec, RandomEffectsSpec};
    24→//! use formula::ModelSpec;
    25→//!
    26→//! // Linear mixed model: y ~ x + (1|group)
    27→//! let fixed_effects = ModelSpec::intercept_only("y");
    28→//! let random_effects = vec![RandomEffectsSpec {
    29→//!     grouping_factor: "group".to_string(),
    30→//!     terms: vec!["1".to_string()],
    31→//!     include_intercept: true,
    32→//! }];
    33→//! let model_spec = MixedModelSpec { fixed_effects, random_effects };
    34→//! let lmm = LinearMixedModel::new(model_spec);
    35→//! // let fit = lmm.fit(&data).unwrap();
    36→//! ```
    37→
    38→#![forbid(unsafe_code)]
    39→#![warn(missing_docs)]
    40→
    41→use faer::Mat;
    42→use formula::ModelSpec;
    43→use ndarray::{Array1, Array2, ArrayView1, ArrayView2};
    44→use optimcore::{pirls, PirlsConfig, OptimError};
    45→use sprs::{CsMat, TriMat};
    46→use std::collections::HashMap;
    47→
    48→/// Mixed model errors
    49→#[derive(thiserror::Error, Debug)]
    50→pub enum MixedModelError {
    51→    /// Convergence failure
    52→    #[error("Failed to converge after {0} iterations")]
    53→    Convergence(usize),
    54→    /// Singular fit (non-identifiable model)
    55→    #[error("Singular fit: random effects are not identifiable")]
    56→    SingularFit,
    57→    /// Invalid model specification
    58→    #[error("Invalid model specification: {0}")]
    59→    InvalidModel(String),
    60→    /// Linear algebra error
    61→    #[error("Linear algebra error: {0}")]
    62→    LinearAlgebra(String),
    63→    /// Optimization error
    64→    #[error("Optimization error: {0}")]
    65→    Optimization(#[from] OptimError),
    66→}
    67→
    68→/// Configuration for mixed model estimation
    69→#[derive(Debug, Clone)]
    70→pub struct MixedModelConfig {
    71→    /// Maximum iterations for optimization
    72→    pub max_iter: usize,
    73→    /// Convergence tolerance for parameters
    74→    pub param_tolerance: f64,
    75→    /// Convergence tolerance for log-likelihood
    76→    pub loglik_tolerance: f64,
    77→    /// Use REML estimation (default: true)
    78→    pub use_reml: bool,
    79→    /// Number of adaptive Gauss-Hermite quadrature points for GLMM
    80→    pub nquad: usize,
    81→    /// Whether to use parallel computation
    82→    pub parallel: bool,
    83→}
    84→
    85→impl Default for MixedModelConfig {
    86→    fn default() -> Self {
    87→        Self {
    88→            max_iter: 200,
    89→            param_tolerance: 1e-6,
    90→            loglik_tolerance: 1e-8,
    91→            use_reml: true,
    92→            nquad: 15,
    93→            parallel: true,
    94→        }
    95→    }
    96→}
    97→
    98→/// Random effects structure specification
    99→#[derive(Debug, Clone)]
   100→pub struct RandomEffectsSpec {
   101→    /// Grouping factor variable name
   102→    pub grouping_factor: String,
   103→    /// Model terms for this random effect
   104→    pub terms: Vec<String>,
   105→    /// Whether to include random intercept
   106→    pub include_intercept: bool,
   107→}
   108→
   109→/// Mixed model specification combining fixed and random effects
   110→#[derive(Debug, Clone)]
   111→pub struct MixedModelSpec {
   112→    /// Fixed effects formula
   113→    pub fixed_effects: ModelSpec,
   114→    /// Random effects specifications
   115→    pub random_effects: Vec<RandomEffectsSpec>,
   116→}
   117→
   118→/// Linear mixed model estimation results
   119→#[derive(Debug)]
   120→pub struct LinearMixedModelFit {
   121→    /// Fixed effects coefficients
   122→    pub fixed_effects: Array1<f64>,
   123→    /// Random effects covariance matrices (one per grouping factor)
   124→    pub random_covariance: HashMap<String, Array2<f64>>,
   125→    /// Predicted random effects (BLUPs)
   126→    pub random_effects_pred: HashMap<String, Array2<f64>>,
   127→    /// Residual variance (σ²)
   128→    pub residual_variance: f64,
   129→    /// Log-likelihood at convergence
   130→    pub log_likelihood: f64,
   131→    /// Whether REML was used
   132→    pub is_reml: bool,
   133→    /// Number of iterations to convergence
   134→    pub iterations: usize,
   135→    /// Fitted values (fixed + random effects)
   136→    pub fitted_values: Array1<f64>,
   137→    /// Residuals
   138→    pub residuals: Array1<f64>,
   139→    /// Number of observations
   140→    pub n_obs: usize,
   141→    /// Degrees of freedom
   142→    pub df_residual: usize,
   143→}
   144→
   145→/// Generalized linear mixed model estimation results
   146→#[derive(Debug)]
   147→pub struct GeneralizedLinearMixedModelFit {
   148→    /// Fixed effects coefficients
   149→    pub fixed_effects: Array1<f64>,
   150→    /// Random effects covariance matrices
   151→    pub random_covariance: HashMap<String, Array2<f64>>,
   152→    /// Predicted random effects (EBLUPs)
   153→    pub random_effects_pred: HashMap<String, Array2<f64>>,
   154→    /// Log-likelihood at convergence
   155→    pub log_likelihood: f64,
   156→    /// Number of iterations to convergence
   157→    pub iterations: usize,
   158→    /// Fitted values on response scale
   159→    pub fitted_values: Array1<f64>,
   160→    /// Linear predictor values
   161→    pub linear_predictor: Array1<f64>,
   162→    /// Deviance residuals
   163→    pub residuals: Array1<f64>,
   164→    /// Number of observations
   165→    pub n_obs: usize,
   166→}
   167→
   168→/// Linear mixed model estimator
   169→pub struct LinearMixedModel {
   170→    /// Model specification
   171→    pub spec: MixedModelSpec,
   172→    /// Estimation configuration
   173→    pub config: MixedModelConfig,
   174→}
   175→
   176→/// Generalized linear mixed model estimator  
   177→pub struct GeneralizedLinearMixedModel<F> {
   178→    /// Model specification
   179→    pub spec: MixedModelSpec,
   180→    /// GLM family
   181→    pub family: F,
   182→    /// Estimation configuration
   183→    pub config: MixedModelConfig,
   184→}
   185→
   186→impl LinearMixedModel {
   187→    /// Create a new linear mixed model
   188→    pub fn new(spec: MixedModelSpec) -> Self {
   189→        Self {
   190→            spec,
   191→            config: MixedModelConfig::default(),
   192→        }
   193→    }
   194→
   195→    /// Create a new linear mixed model with custom configuration
   196→    pub fn with_config(spec: MixedModelSpec, config: MixedModelConfig) -> Self {
   197→        Self { spec, config }
   198→    }
   199→
   200→    /// Fit the linear mixed model using REML or ML estimation
   201→    ///
   202→    /// This implementation uses:
   203→    /// - PIRLS (Penalized Iteratively Reweighted Least Squares) algorithm
   204→    /// - Sparse matrix algorithms for efficient computation with many groups
   205→    /// - Henderson's mixed model equations for optimal computation
   206→    /// - REML or ML estimation for variance components
   207→    pub fn fit(
   208→        &self,
   209→        x_fixed: ArrayView2<f64>,
   210→        y: ArrayView1<f64>,
   211→        groups: &[usize],
   212→    ) -> Result<LinearMixedModelFit, MixedModelError> {
   213→        let n_obs = y.len();
   214→        let n_fixed = x_fixed.ncols();
   215→        
   216→        // Validate inputs
   217→        if x_fixed.nrows() != n_obs {
   218→            return Err(MixedModelError::InvalidModel(
   219→                "Fixed effects design matrix rows don't match response length".to_string(),
   220→            ));
   221→        }
   222→        
   223→        if groups.len() != n_obs {
   224→            return Err(MixedModelError::InvalidModel(
   225→                "Groups vector length doesn't match response length".to_string(),
   226→            ));
   227→        }
   228→        
   229→        // Build sparse random effects design matrix (Z)
   230→        let z_matrix = self.build_random_effects_matrix(groups)?;
   231→        let n_random = z_matrix.cols();
   232→        
   233→        // Configure PIRLS algorithm
   234→        let pirls_config = PirlsConfig {
   235→            max_iter_outer: self.config.max_iter,
   236→            tolerance_outer: self.config.param_tolerance,
   237→            use_reml: self.config.use_reml,
   238→            ..Default::default()
   239→        };
   240→        
   241→        // Fit using PIRLS algorithm
   242→        let pirls_result = pirls(
   243→            x_fixed,
   244→            &z_matrix,
   245→            y,
   246→            None, // Let PIRLS choose initial variance components
   247→            Some(pirls_config),
   248→        )?;
   249→        
   250→        // Calculate fitted values and residuals
   251→        let fitted_fixed = x_fixed.dot(&pirls_result.beta);
   252→        let fitted_random = self.calculate_fitted_random(&z_matrix, &pirls_result.u);
   253→        let fitted_values = &fitted_fixed + &fitted_random;
   254→        let residuals = y.to_owned() - &fitted_values;
   255→        
   256→        // Extract variance components
